module top_module(
	input [3:0] input_data,
	input [1:0] select,
	output reg data_out
);always @ (select or input_data)
		case (select)
			2'b00: data_out = input_data[0];
			2'b01: data_out = input_data[1];
			2'b10: data_out = input_data[2];
			2'b11: data_out = input_data[3];
		endcase

endmodule
